namespace sv_85821e82824147a484e41cabc3ac917a;

public record Channel(int Id, string Name, string Description, int UnreadCount);
public record Message(int Id, int ChannelId, string Author, string Content, DateTime SentAt, int? ReplyToId, List<Reaction> Reactions);
public record Reaction(string Emoji, List<string> Users);
public record ThreadSummary(int RootMessageId, int ReplyCount, DateTime LastReplyAt);

public interface IChatService
{
    Task<List<Channel>> GetChannelsAsync();
    Task<List<Message>> GetMessagesAsync(int channelId, int skip, int take);
    Task<Message> SendMessageAsync(int channelId, string content, int? replyToId);
    Task<List<Message>> GetThreadAsync(int rootMessageId);
    Task AddReactionAsync(int messageId, string emoji);
    Task MarkChannelReadAsync(int channelId);
    Task<List<ThreadSummary>> GetThreadSummariesAsync(int channelId);
}

namespace sv_85821e82824147a484e41cabc3ac917a;

public class StubChatService : IChatService
{
    private readonly List<Channel> _channels =
    [
        new(1, "general", "Company-wide announcements and chat", 3),
        new(2, "engineering", "Engineering team discussions", 0),
        new(3, "design", "Design reviews and feedback", 1),
        new(4, "random", "Non-work banter and water cooler chat", 0),
    ];

    private readonly List<Message> _messages =
    [
        new(1, 1, "Alice", "Hey everyone! Welcome to the new chat app 🎉", DateTime.UtcNow.AddHours(-5), null, [new("🎉", ["Bob", "Carol"]), new("👍", ["Dave"])]),
        new(2, 1, "Bob", "Looks great! When are we rolling this out?", DateTime.UtcNow.AddHours(-4), null, []),
        new(3, 1, "Carol", "Love the new design. Really clean UI.", DateTime.UtcNow.AddHours(-3), null, [new("❤️", ["Alice"])]),
        new(4, 1, "Dave", "Quick question — does this support threads?", DateTime.UtcNow.AddHours(-2), null, []),
        new(5, 1, "Alice", "Yes it does! Click the reply button on any message.", DateTime.UtcNow.AddMinutes(-90), null, [new("👍", ["Dave"])]),
        new(6, 1, "Eve", "Just joined the channel. Hi all!", DateTime.UtcNow.AddMinutes(-30), null, []),
        new(7, 1, "Bob", "Welcome Eve! 👋", DateTime.UtcNow.AddMinutes(-25), null, []),
        new(8, 1, "Carol", "Has anyone seen the latest deployment metrics?", DateTime.UtcNow.AddMinutes(-10), null, []),
        new(9, 1, "Dave", "I'll pull them up now.", DateTime.UtcNow.AddMinutes(-5), null, []),
        new(10, 1, "Alice", "Let's discuss in the engineering channel.", DateTime.UtcNow.AddMinutes(-2), null, []),
        new(11, 2, "Alice", "Sprint planning is tomorrow at 10am.", DateTime.UtcNow.AddHours(-6), null, []),
        new(12, 2, "Bob", "I'll prepare the backlog review.", DateTime.UtcNow.AddHours(-5), null, [new("👍", ["Alice", "Carol"])]),
        new(13, 2, "Carol", "Can we also discuss the API redesign?", DateTime.UtcNow.AddHours(-3), null, []),
        new(14, 3, "Dave", "New mockups are uploaded to Figma.", DateTime.UtcNow.AddHours(-1), null, [new("👀", ["Eve", "Alice"])]),
    ];

    private readonly List<Message> _threadReplies =
    [
        new(101, 1, "Bob", "I think next week is the target.", DateTime.UtcNow.AddHours(-3).AddMinutes(-30), 4, []),
        new(102, 1, "Carol", "We should do a beta first.", DateTime.UtcNow.AddHours(-3), 4, [new("👍", ["Alice"])]),
        new(103, 1, "Dave", "Agreed — beta next Monday?", DateTime.UtcNow.AddHours(-2).AddMinutes(-30), 4, []),
        new(104, 1, "Alice", "Yes, that metric is way up — great work!", DateTime.UtcNow.AddMinutes(-4), 8, []),
        new(105, 1, "Eve", "Here's the link: https://metrics.example.com", DateTime.UtcNow.AddMinutes(-2), 8, []),
    ];

    private int _nextId = 200;

    public Task<List<Channel>> GetChannelsAsync() =>
        Task.FromResult(_channels.ToList());

    public Task<List<Message>> GetMessagesAsync(int channelId, int skip, int take)
    {
        var messages = _messages
            .Where(m => m.ChannelId == channelId)
            .OrderBy(m => m.SentAt)
            .Skip(skip)
            .Take(take)
            .ToList();
        return Task.FromResult(messages);
    }

    public Task<Message> SendMessageAsync(int channelId, string content, int? replyToId)
    {
        var message = new Message(Interlocked.Increment(ref _nextId), channelId, "You", content, DateTime.UtcNow, replyToId, []);
        if (replyToId is null)
            _messages.Add(message);
        else
            _threadReplies.Add(message);
        return Task.FromResult(message);
    }

    public Task<List<Message>> GetThreadAsync(int rootMessageId)
    {
        var replies = _threadReplies
            .Where(m => m.ReplyToId == rootMessageId)
            .OrderBy(m => m.SentAt)
            .ToList();
        return Task.FromResult(replies);
    }

    public Task AddReactionAsync(int messageId, string emoji)
    {
        var msg = _messages.Concat(_threadReplies).FirstOrDefault(m => m.Id == messageId);
        if (msg is not null)
        {
            var existing = msg.Reactions.FirstOrDefault(r => r.Emoji == emoji);
            if (existing is not null)
                existing.Users.Add("You");
            else
                msg.Reactions.Add(new Reaction(emoji, ["You"]));
        }
        return Task.CompletedTask;
    }

    public Task MarkChannelReadAsync(int channelId)
    {
        var idx = _channels.FindIndex(c => c.Id == channelId);
        if (idx >= 0)
            _channels[idx] = _channels[idx] with { UnreadCount = 0 };
        return Task.CompletedTask;
    }

    public Task<List<ThreadSummary>> GetThreadSummariesAsync(int channelId)
    {
        var rootIds = _threadReplies
            .Where(r => _messages.Any(m => m.Id == r.ReplyToId && m.ChannelId == channelId))
            .GroupBy(r => r.ReplyToId!.Value)
            .Select(g => new ThreadSummary(g.Key, g.Count(), g.Max(r => r.SentAt)))
            .ToList();
        return Task.FromResult(rootIds);
    }
}

.channel-item {
    padding: 8px 12px;
    cursor: pointer;
    border-radius: 6px;
    margin: 2px 8px;
    transition: background-color 0.15s;
}

.channel-item:hover {
    background-color: rgba(255, 255, 255, 0.08);
}

.channel-item.active {
    background-color: rgba(255, 255, 255, 0.15);
}

.channel-header-row {
    display: flex;
    align-items: center;
    justify-content: space-between;
}

.channel-name {
    font-weight: 600;
    font-size: 0.95rem;
    color: #e0e0e0;
}

.channel-item.active .channel-name {
    color: #fff;
}

.channel-description {
    font-size: 0.78rem;
    color: #999;
    white-space: nowrap;
    overflow: hidden;
    text-overflow: ellipsis;
    margin-top: 2px;
}

.unread-badge {
    background-color: #e74c3c;
    color: #fff;
    font-size: 0.7rem;
    font-weight: 700;
    padding: 1px 6px;
    border-radius: 10px;
    min-width: 18px;
    text-align: center;
}

.channel-sidebar {
    width: 100%;
    height: 100%;
    background-color: #1e1e2e;
    color: #ccc;
    overflow-y: auto;
    padding: 8px 0;
}

.sidebar-title {
    font-size: 0.85rem;
    text-transform: uppercase;
    letter-spacing: 0.05em;
    color: #888;
    padding: 8px 20px 4px;
    margin: 0;
}

.message-input {
    display: flex;
    gap: 8px;
    padding: 12px 16px;
    border-top: 1px solid #3a3a4a;
    background: #2a2a3a;
    align-items: flex-end;
}

.message-input textarea {
    flex: 1;
    resize: none;
    border: 1px solid #444;
    border-radius: 6px;
    padding: 8px 12px;
    font-size: 0.9rem;
    font-family: inherit;
    background: #1e1e2e;
    color: #e0e0e0;
    outline: none;
    min-height: 38px;
    max-height: 120px;
}

.message-input textarea:focus {
    border-color: #5b6eae;
}

.send-btn {
    background-color: #5b6eae;
    color: #fff;
    border: none;
    border-radius: 6px;
    padding: 8px 16px;
    font-size: 0.85rem;
    font-weight: 600;
    cursor: pointer;
    white-space: nowrap;
    transition: background-color 0.15s;
}

.send-btn:hover:not(:disabled) {
    background-color: #6e80c0;
}

.send-btn:disabled {
    opacity: 0.5;
    cursor: not-allowed;
}

