    public Task<List<Message>> GetMessagesAsync(int channelId, int skip, int take)
    {
        var messages = _messages
            .Where(m => m.ChannelId == channelId)
            .OrderBy(m => m.SentAt)
            .Skip(skip)
            .Take(take)
            .ToList();
        return Task.FromResult(messages);
