@implements IAsyncDisposable
@inject IJSRuntime JS

<div class="message-area">
    <div class="area-header">
        @if (Channel is not null)
        {
            <h2 class="area-channel-name"># @Channel.Name</h2>
            <span class="area-channel-desc">@Channel.Description</span>
        }
    </div>

    <div class="message-list" @ref="_scrollContainer">
        <div @ref="_sentinel" class="scroll-sentinel">
            @if (IsLoadingMore)
            {
                <span class="loading-indicator">Loading older messages…</span>
            }
        </div>

        @foreach (var message in Messages)
        {
            <MessageItem Message="message"
                         ThreadSummary="GetThreadSummary(message.Id)"
                         OnOpenThread="OnOpenThread"
                         OnReact="OnReact" />
        }
    </div>

    <MessageInput Placeholder="@($"Message #{Channel?.Name ?? "channel"}…")"
                  ButtonText="Send"
                  OnSend="OnSendMessage" />
</div>

@code {
    [Parameter, EditorRequired] public List<Message> Messages { get; set; } = [];
    [Parameter] public Channel? Channel { get; set; }
    [Parameter] public Dictionary<int, ThreadSummary> ThreadSummaries { get; set; } = new();
    [Parameter] public bool IsLoadingMore { get; set; }
    [Parameter] public EventCallback<int> OnOpenThread { get; set; }
    [Parameter] public EventCallback<(int MessageId, string Emoji)> OnReact { get; set; }
    [Parameter] public EventCallback<string> OnSendMessage { get; set; }
    [Parameter] public EventCallback OnLoadMore { get; set; }

    private ElementReference _scrollContainer;
    private ElementReference _sentinel;
    private IJSObjectReference? _module;
    private DotNetObjectReference<MessageArea>? _dotNetRef;
    private bool _observerInitialized;

    private ThreadSummary? GetThreadSummary(int messageId) =>
        ThreadSummaries.GetValueOrDefault(messageId);

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (firstRender)
        {
            await InitScrollObserver();
        }
    }

    private async Task InitScrollObserver()
    {
        if (_observerInitialized) return;
        try
        {
            _module = await JS.InvokeAsync<IJSObjectReference>(
                "import", "./Components/Chat/MessageArea.razor.js");
            _dotNetRef = DotNetObjectReference.Create(this);
            await _module.InvokeVoidAsync("initScrollObserver", _sentinel, _dotNetRef);
            _observerInitialized = true;
        }
        catch
        {
            // JS interop may fail during prerender
        }
    }

    [JSInvokable]
    public async Task OnScrolledToTop()
    {
        await OnLoadMore.InvokeAsync();
    }

    public async ValueTask DisposeAsync()
    {
        if (_module is not null)
        {
            try
            {
                await _module.InvokeVoidAsync("disposeScrollObserver", _sentinel);
                await _module.DisposeAsync();
            }
            catch
            {
                // Component may dispose after circuit is gone
            }
        }
        _dotNetRef?.Dispose();
    }
}

.message-area {
    display: flex;
    flex-direction: column;
    height: 100%;
    background: #25253a;
    min-width: 0;
}

.area-header {
    padding: 12px 20px;
    border-bottom: 1px solid #3a3a4a;
    flex-shrink: 0;
}

.area-channel-name {
    margin: 0;
