    padding: 8px 0;
    display: flex;
    flex-direction: column;
}

.scroll-sentinel {
    min-height: 1px;
    flex-shrink: 0;
    text-align: center;
}

.loading-indicator {
    display: inline-block;
    padding: 8px 16px;
    font-size: 0.8rem;
    color: #888;
}

export function initScrollObserver(sentinel, dotNetRef) {
    if (!sentinel) return;

    const observer = new IntersectionObserver((entries) => {
        if (entries[0].isIntersecting) {
            dotNetRef.invokeMethodAsync('OnScrolledToTop');
        }
    }, { threshold: 0.1 });

    observer.observe(sentinel);
    sentinel._scrollObserver = observer;
}

export function disposeScrollObserver(sentinel) {
    if (sentinel?._scrollObserver) {
        sentinel._scrollObserver.disconnect();
        delete sentinel._scrollObserver;
    }
}

