.thread-panel {
    display: flex;
    flex-direction: column;
    height: 100%;
    background: #1e1e2e;
    border-left: 1px solid #3a3a4a;
    min-width: 0;
}

.thread-header {
    display: flex;
    align-items: center;
    justify-content: space-between;
    padding: 12px 16px;
    border-bottom: 1px solid #3a3a4a;
    flex-shrink: 0;
}

.thread-header h3 {
    margin: 0;
    font-size: 1rem;
    color: #fff;
    font-weight: 700;
}

.close-btn {
    background: none;
    border: none;
    color: #999;
    font-size: 1.1rem;
    cursor: pointer;
    padding: 4px 8px;
    border-radius: 4px;
    transition: background-color 0.1s, color 0.1s;
}

.close-btn:hover {
    background-color: rgba(255, 255, 255, 0.1);
    color: #fff;
}

.thread-root-quote {
    margin: 12px 16px;
    padding: 10px 12px;
    background: rgba(255, 255, 255, 0.05);
    border-left: 3px solid #5b6eae;
    border-radius: 0 6px 6px 0;
}

.quote-author {
    font-weight: 700;
    font-size: 0.85rem;
    color: #ccc;
    margin-bottom: 2px;
}

.quote-content {
    font-size: 0.85rem;
    color: #aaa;
    line-height: 1.4;
}

.thread-replies {
    flex: 1;
    overflow-y: auto;
    padding: 4px 0;
}

.no-replies {
    text-align: center;
    color: #666;
    font-size: 0.85rem;
    padding: 24px 16px;
}

.thread-reply {
    padding: 6px 16px;
}

.thread-reply:hover {
    background-color: rgba(255, 255, 255, 0.03);
}

.reply-header {
    display: flex;
    align-items: baseline;
    gap: 8px;
    margin-bottom: 2px;
}

.reply-author {
    font-weight: 700;
    font-size: 0.85rem;
    color: #e0e0e0;
}

.reply-timestamp {
    font-size: 0.72rem;
    color: #777;
}

.reply-content {
    font-size: 0.85rem;
    color: #d0d0d0;
    line-height: 1.4;
}

