@page "/chat"
@using sv_85821e82824147a484e41cabc3ac917a.Components.Chat
@rendermode InteractiveServer
@inject IChatService ChatService

<PageTitle>Chat</PageTitle>

<div class="chat-layout">
    <div class="chat-sidebar">
        <ChannelSidebar Channels="_channels"
                        SelectedChannelId="_selectedChannelId"
                        OnChannelSelected="SelectChannel" />
    </div>

    <div class="chat-main @(_isThreadOpen ? "" : "expanded")">
        <MessageArea Channel="_selectedChannel"
                     Messages="_messages"
                     ThreadSummaries="_threadSummaries"
                     IsLoadingMore="_isLoadingMore"
                     OnOpenThread="OpenThread"
                     OnReact="AddReaction"
                     OnSendMessage="SendMessage"
                     OnLoadMore="LoadOlderMessages" />
    </div>

    @if (_isThreadOpen)
    {
        <div class="chat-thread">
            <ThreadPanel RootMessage="_threadRootMessage"
                         Replies="_threadReplies"
                         OnClose="CloseThread"
                         OnSendReply="SendThreadReply" />
        </div>
    }
</div>

@code {
    private List<Channel> _channels = [];
    private List<Message> _messages = [];
    private List<Message> _threadReplies = [];
    private Dictionary<int, ThreadSummary> _threadSummaries = new();

    private Channel? _selectedChannel;
    private int? _selectedChannelId;

    private Message? _threadRootMessage;
    private bool _isThreadOpen;
    private bool _isLoadingMore;

    private const int PageSize = 20;

    protected override async Task OnInitializedAsync()
    {
        _channels = await ChatService.GetChannelsAsync();
        if (_channels.Count > 0)
        {
            await SelectChannel(_channels[0].Id);
        }
    }

    private async Task SelectChannel(int channelId)
    {
        _selectedChannelId = channelId;
        _selectedChannel = _channels.FirstOrDefault(c => c.Id == channelId);
        _messages = await ChatService.GetMessagesAsync(channelId, 0, PageSize);
        _isThreadOpen = false;
        _threadReplies = [];
        _threadRootMessage = null;

        var summaries = await ChatService.GetThreadSummariesAsync(channelId);
        _threadSummaries = summaries.ToDictionary(s => s.RootMessageId);

        await ChatService.MarkChannelReadAsync(channelId);
        _channels = await ChatService.GetChannelsAsync();
    }

    private async Task SendMessage(string content)
    {
        if (_selectedChannelId is null) return;
        var msg = await ChatService.SendMessageAsync(_selectedChannelId.Value, content, null);
        _messages.Add(msg);
    }

    private async Task LoadOlderMessages()
    {
        if (_selectedChannelId is null || _isLoadingMore) return;

        _isLoadingMore = true;
        StateHasChanged();

        var older = await ChatService.GetMessagesAsync(_selectedChannelId.Value, _messages.Count, PageSize);
        if (older.Count > 0)
        {
            _messages.InsertRange(0, older);
        }

        _isLoadingMore = false;
    }

    private async Task OpenThread(int messageId)
    {
        _threadRootMessage = _messages.FirstOrDefault(m => m.Id == messageId);
        _threadReplies = await ChatService.GetThreadAsync(messageId);
        _isThreadOpen = true;

        // Update the thread summary for this message
        if (_threadReplies.Count > 0)
        {
            _threadSummaries[messageId] = new ThreadSummary(
                messageId, _threadReplies.Count, _threadReplies[^1].SentAt);
        }
    }

    private void CloseThread()
    {
        _isThreadOpen = false;
        _threadRootMessage = null;
        _threadReplies = [];
    }

    private async Task SendThreadReply(string content)
    {
        if (_threadRootMessage is null) return;
        var reply = await ChatService.SendMessageAsync(
            _threadRootMessage.ChannelId, content, _threadRootMessage.Id);
        _threadReplies.Add(reply);

        // Update thread summary
        _threadSummaries[_threadRootMessage.Id] = new ThreadSummary(
            _threadRootMessage.Id, _threadReplies.Count, reply.SentAt);
    }

    private async Task AddReaction((int MessageId, string Emoji) args)
    {
        await ChatService.AddReactionAsync(args.MessageId, args.Emoji);
        // Refresh messages to show updated reactions
        if (_selectedChannelId is not null)
        {
            _messages = await ChatService.GetMessagesAsync(_selectedChannelId.Value, 0, _messages.Count);
        }
    }
}

.chat-layout {
    display: flex;
    height: 100vh;
    overflow: hidden;
    background: #25253a;
    color: #e0e0e0;
    font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, Helvetica, Arial, sans-serif;
}

.chat-sidebar {
    width: 20%;
    min-width: 200px;
    max-width: 280px;
    flex-shrink: 0;
    border-right: 1px solid #3a3a4a;
}

.chat-main {
    flex: 55;
    min-width: 0;
    transition: flex 0.2s ease;
}

.chat-main.expanded {
    flex: 80;
}

.chat-thread {
    flex: 25;
    min-width: 280px;
    max-width: 400px;
    flex-shrink: 0;
}

